export function createGeistIcon(
  name: GeistIconName,
  options: { className?: string; title?: string; size?: number } = {},
): SVGSVGElement {
  const icon = ICONS[name];
  const svg = document.createElementNS(SVG_NS, 'svg');
  svg.setAttribute('viewBox', icon.viewBox);
  svg.setAttribute('width', String(options.size || 16));
  svg.setAttribute('height', String(options.size || 16));
  svg.setAttribute('fill', 'currentColor');
  svg.setAttribute('aria-hidden', options.title ? 'false' : 'true');
  svg.setAttribute('focusable', 'false');
  svg.classList.add('geist-icon');
  if (options.className) svg.classList.add(...options.className.split(' ').filter(Boolean));
  if (options.title) {
    const title = document.createElementNS(SVG_NS, 'title');
    title.textContent = options.title;
    svg.appendChild(title);
  }
  for (const attrs of icon.paths) {
    const path = document.createElementNS(SVG_NS, 'path');
    for (const [key, value] of Object.entries(attrs)) {
      if (value === undefined) continue;
      path.setAttribute(key.replace(/[A-Z]/g, (letter) => `-${letter.toLowerCase()}`), value);
    }
    if (!attrs.fill && !attrs.stroke) path.setAttribute('fill', 'currentColor');
    svg.appendChild(path);
  }
  return svg;
}
